<?php namespace App\Http\Controllers\Api\V1; use App\Http\Controllers\Controller; use App\Services\CaseService; use App\Services\InvoiceService; use App\Traits\ApiResponseTrait; use Illuminate\Http\JsonResponse; /** * @OA\Info(title="Performance Dashboard API", version="1.0.0") */ class PerformanceDashboardController extends Controller { use ApiResponseTrait; protected CaseService $caseService; protected InvoiceService $invoiceService; public function __construct(CaseService $caseService, InvoiceService $invoiceService) { $this->caseService = $caseService; $this->invoiceService = $invoiceService; } /** * @OA\Get( * path="/api/v1/dashboard/performance", * summary="استرجاع إحصائيات الأداء المجمعة", * tags={"Dashboard"}, * @OA\Response(response=200, description="نجاح العملية") * ) */ public function getPerformanceStats(): JsonResponse { $caseStats = $this->caseService->getDashboardStatistics(); $invoiceStats = $this->invoiceService->getFinancialOverview(); $data = [ 'cases' => $caseStats, 'finances' => $invoiceStats, 'generated_at' => now()->toDateTimeString() ]; return $this->successResponse($data, 'تم جلب إحصائيات الأداء بنجاح'); } }